import json
import os

# The query results should be available as variables
# Let's try accessing each query result directly

# From query_db_10 (high-rated books from 2020+)
high_rated_books = None
book_data_path = "var_functions.query_db_20"

if os.path.exists(book_data_path):
    with open(book_data_path, 'r') as f:
        high_rated_books = json.load(f)

# From query_db_32 (children's books)
childrens_books = None  
childrens_path = "var_functions.query_db_32"

if os.path.exists(childrens_path):
    with open(childrens_path, 'r') as f:
        childrens_books = json.load(f)

print("__RESULT__:")
if high_rated_books and childrens_books:
    # Create lookup for children's books
    childrens_book_ids = set()
    for book in childrens_books:
        book_id = book.get('book_id', '')
        if book_id and 'children' in book.get('categories', '').lower():
            childrens_book_ids.add(book_id)

    # Find high-rated children's books
    high_rated_childrens = []
    for rating in high_rated_books:
        purchase_id = rating.get('purchase_id', '')
        match_book_id = purchase_id.replace('purchaseid_', 'bookid_')

        if match_book_id in childrens_book_ids:
            # Find the matching book title
            book_title = None
            for book in childrens_books:
                if book.get('book_id') == match_book_id:
                    book_title = book.get('title')
                    break

            high_rated_childrens.append({
                'title': book_title,
                'book_id': match_book_id,
                'avg_rating': float(rating.get('avg_rating', 0)),
                'review_count': int(rating.get('review_count', 0))
            })

    result = {
        'high_rated_childrens_books': high_rated_childrens,
        'total_found': len(high_rated_childrens)
    }
else:
    result = {
        'error': 'Could not load data',
        'high_rated_exists': high_rated_books is not None,
        'childrens_exists': childrens_books is not None
    }

print(json.dumps(result))

